            "system_requirements": ["JDK 17", "PostgreSQL 15", "Redis 7", "Kafka 3.5（可选，初期可省略用内存队列替代，后续扩容再部署）"],
            "lock_rationale": "仅锁定核心依赖的LTS稳定版本，非核心依赖允许按需选择，兼顾稳定性与灵活性，避免无意义的版本升级带来的兼容成本，仅在有明确安全/功能需求时升级核心依赖。"
        },
        "architecture": {
            "modules": [
                {
                    "name": "领域核心层",
                    "responsibility": "存放纯财务业务规则、核心计算逻辑、事件定义、权限规则、验收规则，完全不依赖任何外部组件，定义所有对外交互的抽象端口",
                    "dependencies": [],
